// Obtener los datos de entrada
const items = $('AI_Agent').all();

return items.map(item => {
    // Acceder al contenido del mensaje del elemento actual
    let text = item.json.output || '';

    // Eliminar los saltos de página dobles y normalizar
    text = text.replace(/\n\n/g, '\n').replace(/\n/g, '\\n');

    // Retornar el objeto modificado
    return {
        json: {
            ...item.json, // Mantiene otros datos del objeto original
            message: {
                content: text
            }
        }
    };
});

