// CÓDIGO PARA EL NODO "Code" - Nombre: "Filter_Valid_Parts"
// Ubicar DESPUÉS de "Structured Output Parser" y ANTES de "Split_Out"

// Obtener la respuesta del Structured Output Parser
const input = $input.first().json;

console.log("Input recibido del Output Parser:", JSON.stringify(input, null, 2));

// Acceder a la estructura correcta: output.Response
const response = input.output?.Response || input.Response || input;

// Función para validar si una parte tiene contenido válido
function esParteValida(contenido) {
  if (!contenido) return false;

  const texto = String(contenido).trim();

  // Verificar longitud mínima
  if (texto.length < 10) return false;

  // Valores que consideramos vacíos
  const valoresVacios = [
    "", 
    "null", 
    "undefined", 
    "N/A", 
    "Sin contenido",
    "No disponible",
    " ",
    "...",
    "---",
    "null",
    "undefined"
  ];

  return !valoresVacios.includes(texto.toLowerCase());
}

// Crear objeto de respuesta solo con partes válidas
const respuestaFiltrada = {};

// Verificar y agregar solo las partes que tienen contenido
if (esParteValida(response.Parte1)) {
  respuestaFiltrada.Parte1 = response.Parte1.trim();
}

if (esParteValida(response.Parte2)) {
  respuestaFiltrada.Parte2 = response.Parte2.trim();
}

if (esParteValida(response.Parte3)) {
  respuestaFiltrada.Parte3 = response.Parte3.trim();
}

// Contar partes válidas
const partesValidas = Object.keys(respuestaFiltrada).length;

console.log(`Partes válidas encontradas: ${partesValidas}`);
console.log("Respuesta filtrada:", JSON.stringify(respuestaFiltrada, null, 2));

// Si no hay partes válidas, crear una respuesta por defecto
if (partesValidas === 0) {
  respuestaFiltrada.Parte1 = "Lo siento, no pude procesar la respuesta correctamente.";
  console.log("ADVERTENCIA: No se encontraron partes válidas, usando respuesta por defecto");
}

// Retornar la respuesta filtrada en el mismo formato que espera Split_Out
return [{ json: { output: { Response: respuestaFiltrada } } }];

